/**
 * Minute Mantra — Push Notification Service Worker Extension
 * 
 * This file handles push notifications and notification clicks.
 * It is loaded separately from the Workbox-generated service worker.
 * 
 * NOTE: The main service worker (sw.js) is auto-generated by vite-plugin-pwa.
 * Push notification handling is registered in main.jsx via navigator.serviceWorker.
 */

const CDN = 'https://minute-mantra.b-cdn.net';

self.addEventListener('push', (event) => {
  if (!event.data) return;

  let payload;
  try {
    payload = event.data.json();
  } catch (e) {
    payload = { title: 'Minute Mantra', body: event.data.text() };
  }

  const options = {
    body: payload.body || 'Your morning mantra is ready.',
    icon: payload.icon || `${CDN}/icons/icon-192.png`,
    badge: payload.badge || `${CDN}/icons/badge-72.png`,
    image: payload.image || null,
    tag: payload.tag || 'morning-mantra',
    renotify: payload.renotify !== false,
    requireInteraction: false,
    silent: false,
    data: {
      url: payload.url || '/',
      mantra_id: payload.mantra_id || null,
    },
    actions: [
      { action: 'open', title: 'Chant Now' },
      { action: 'dismiss', title: 'Dismiss' },
    ],
  };

  event.waitUntil(
    self.registration.showNotification(payload.title || 'Minute Mantra', options)
  );
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  if (event.action === 'dismiss') return;

  const url = event.notification.data?.url || '/';

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then((clientList) => {
      // Focus existing window if open
      for (const client of clientList) {
        if (client.url.includes(self.location.origin) && 'focus' in client) {
          client.navigate(url);
          return client.focus();
        }
      }
      // Open new window
      if (clients.openWindow) {
        return clients.openWindow(url);
      }
    })
  );
});
